12.query:
fetch logs //, scanLimitGBytes: 500, samplingRatio: 1000
| filter matchesValue(winlog.eventid, "4720") OR matchesValue(winlog.eventid, "4738") OR matchesValue(winlog.eventid, "4722") OR matchesValue(winlog.eventid, "4725") OR matchesValue(winlog.eventid, "4726")
| filterout matchesPhrase(content, "The EventSystem sub system is suppressing duplicate event log entries for a duration of 86400 seconds")
| fieldsAdd EventType = if(winlog.eventid == "4720", "Created",
    else: if(winlog.eventid == "4738", "Modified",
    else: if(winlog.eventid == "4722", "Enabled",
    else: if(winlog.eventid == "4725", "Disabled",
    else: "Deleted"))))
| makeTimeseries count(), by: EventType, time:{timestamp}, interval:5m

22.query:
fetch logs //, scanLimitGBytes: 500, samplingRatio: 1000
| filter matchesValue(winlog.eventid, "4720") OR matchesValue(winlog.eventid, "4738") OR matchesValue(winlog.eventid, "4725") OR matchesValue(winlog.eventid, "4726")
| filterout matchesPhrase(content, "The EventSystem sub system is suppressing duplicate event log entries for a duration of 86400 seconds")
| parse content, """DATA 'Account Name:\t\t' DATA:PerformedBy EOL
DATA 'Account Domain:\t\t' DATA:PerformedByDomain EOL"""
| filterOut contains(PerformedBy, "$")
| fieldsAdd EventType = if(winlog.eventid == "4720", "Created",
    else: if(winlog.eventid == "4738", "Modified",
    else: if(winlog.eventid == "4725", "Disabled",
    else: "Deleted")))
| summarize count = count(), by:{PerformedBy, EventType}
| sort count desc
